/**
 * 定义二叉树的结构
 */
declare class TreeNode<T> {
    data: T;
    left: TreeNode<T> | undefined;
    right: TreeNode<T> | undefined;
    count: number;
    preOrder: Array<T>;
    centerOrder: Array<T>;
    postOrder: Array<T>;
    constructor(data: T, left: TreeNode<T> | undefined, right: TreeNode<T> | undefined);
}
/**
 * 定义二叉树的操作
 */
declare class BinaryTree<T> {
    root: TreeNode<T> | undefined;
    constructor();
    insert(data: T): void;
    /**
     * 根据元素值 寻找 节点
     * @param data
     */
    find(data: T): TreeNode<T> | undefined;
    /**
     * 获取根节点
     */
    getRoot(): TreeNode<T> | undefined;
    /**
     * 删除节点
     */
    removeNode(data: T): void;
    _removeNode(curNode: TreeNode<T> | undefined, data: T): TreeNode<T> | undefined;
    /**
     * 获取最大节点
     * @param curNode
     */
    getMaxNode(node?: TreeNode<T>): TreeNode<T>;
    /**
     * 获取最小节点
     * @param curNode
     */
    getMinNode(node?: TreeNode<T>): TreeNode<T>;
    /**
     * 先序遍历，遍历结束之后，可以通过 bt.getRoot().preOrder 获取遍历以后的元素数组
     * @param root
     */
    preOrderTraversal(root: TreeNode<T> | undefined): undefined;
    /**
     * 中序遍历，遍历结束之后，可以通过 bt.getRoot().centerOrder 获取遍历以后的元素数组
     * @param root
     */
    centerOrderTraversal(root: TreeNode<T> | undefined): undefined;
    /**
     * 后序遍序遍历，遍历结束之后，可以通过 bt.getRoot().postOrder 获取遍历以后的元素数组
     * @param root
     */
    postOrderTraversal(root: TreeNode<T> | undefined): undefined;
}
declare const _default: BinaryTree<unknown>;
export default _default;
